def adapt(a_payload):
    import datetime
    import re

    order_id = a_payload["order_id"]
    order_date = a_payload["order_date"]

    if not isinstance(order_id, int) or isinstance(order_id, bool):
        raise TypeError("order_id must be an integer")
    if not isinstance(order_date, str):
        raise TypeError("order_date must be a non-null string")
    if re.fullmatch(r"[0-9]{2}/[0-9]{2}/[0-9]{4}", order_date) is None:
        raise ValueError("order_date must use DD/MM/YYYY format")

    day, month, year = map(int, order_date.split("/"))
    parsed_date = datetime.date(year, month, day)

    return {"orderId": order_id, "orderDate": parsed_date.isoformat()}

